import{_ as r,o as t,c as o,a2 as e}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"G02: 董事高階經理人異動審計 - 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/2492_華新科/20260512/G02_董事高階經理人異動審計.md","filePath":"審計報告庫/經營審計/2492_華新科/20260512/G02_董事高階經理人異動審計.md"}'),l={name:"審計報告庫/經營審計/2492_華新科/20260512/G02_董事高階經理人異動審計.md"};function n(i,a,s,h,d,_){return t(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="g02-董事高階經理人異動審計-經營審計專家報告" tabindex="-1">G02: 董事高階經理人異動審計 - 經營審計專家報告 <a class="header-anchor" href="#g02-董事高階經理人異動審計-經營審計專家報告" aria-label="Permalink to &quot;G02: 董事高階經理人異動審計 - 經營審計專家報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>董事會與高階經理人近三年是否有非正常異動？這對公司目前經營決策與管理穩定度有何影響？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：2023-2026華新科高階異動屬計畫性接班，非危機導向。總經理輪調最大變動，屬焦佑衡交棒藍圖。稽核主管3年2次偏高為次要訊號。治理穩定度偏優，接班約60%。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：截至2026年5月12日最新公開資料</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A-（良）</strong>：2023-2026年間共發生9筆主要異動，其中6筆為公開計畫性接班（總經理輪調、董事改選），2筆為正常退休/職務調整（稽核主管2022退休、2025調整），1筆為獨立董事解任（2023年1月，理由合理）。核心關鍵位階中，董事長（焦佑衡，34年任職）、財務主管（葉澤光，長期任職）、發言人（李定珠，長期任職）均無異常異動。唯一需關注：稽核主管3年內更換2次（2022退休→2025職務調整），屬於邊際偏高頻率，建議追蹤新任稽核主管李惠雪（原品管部經理）之專業適格性。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-核心位階異動明細" tabindex="-1">1. 核心位階異動明細 <a class="header-anchor" href="#_1-核心位階異動明細" aria-label="Permalink to &quot;1. 核心位階異動明細&quot;">​</a></h3><p><strong>董事長</strong>：焦佑衡續任，2024年6月及2025年6月董事改選後連任。</p><p><strong>總經理</strong>：2023年6月顧立荊轉副董事長，由佳邦總經理曾明燦接任，PSA輪調一環，理由具說服力。曾明燦續任至2026年，2025年10月兼任信昌電法人董事代表。</p><p><strong>財務主管</strong>：葉澤光續任財會主管，發言人李定珠長期任職，均無異常。</p><p><strong>稽核主管</strong>：2022年9月退休、2025年1月職務調整（黃→李，品管部），3年2次偏高需追蹤。</p><p><strong>獨董</strong>：2023年1月一名解任，2025年范伯康、黃倩君、張可欣全數留任。范伯康連任逾三屆因其專長獲續提名，邊際合規。</p><h3 id="_2-時點偵測" tabindex="-1">2. 時點偵測 <a class="header-anchor" href="#_2-時點偵測" aria-label="Permalink to &quot;2. 時點偵測&quot;">​</a></h3><p>經交叉比對，無異動發生於財報發布前夕或重大收購期。總經理輪調（6月底）與董事長改選時序均為常規組織調整，無異常。</p><h3 id="_3-接班斷代風險" tabindex="-1">3. 接班斷代風險 <a class="header-anchor" href="#_3-接班斷代風險" aria-label="Permalink to &quot;3. 接班斷代風險&quot;">​</a></h3><p>焦佑衡正從經營者轉型為投資者，計畫性傳承中。風險點：PSA平台過去依賴其個人領導力，換血後跨公司協同可能弱化。曾明燦（佳邦背景）與華新科MLCC主業不同質，文化融合待觀察。</p><h3 id="_4-異動量化指標" tabindex="-1">4. 異動量化指標 <a class="header-anchor" href="#_4-異動量化指標" aria-label="Permalink to &quot;4. 異動量化指標&quot;">​</a></h3><ul><li><strong>年度異動率</strong>：2023年3筆、2024年2筆、2025年4筆，扣除董事選舉例行事項約0.5次/年，屬正常。</li><li><strong>總經理磨合期</strong>：曾明燦接任逾1,045天，跨越景氣循環，磨合完成。</li><li><strong>核心留任年資</strong>：董事長34年、發言人&gt;10年、財會主管&gt;5年，資歷深厚。</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>稽核主管3年2換屬管理警訊</strong>：雖有合理理由（退休+職務調整），但3年2度異動代表內控監督鏈不穩定。新任稽核主管李惠雪由品管部轉任，欠缺財務/稽核專業背景，獨立性與專業適格性有待驗證。</li><li><strong>PSA平台依賴個人領導的集中風險</strong>：焦佑衡2025年宣告逐步退居幕後，但其主持34年的PSA事業群（十家公司）依賴其個人協調能力。若未來各子公司總經理間缺乏相互制衡機制，可能出現「聯而不盟」的碎片化風險。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>交班結構設計優於同業</strong>：2023年啟動的全面輪調制度同步影響華新科、佳邦、信昌電、久尹等子公司，非單一公司孤軍換血。輪調路徑明確（顧立荊→副董、曾明燦→華新科總座、洪志謀→佳邦），屬SOP化的組織發展。</li><li><strong>財務與發言人系統持續穩定</strong>：在總經理層級換血過程中，財會主管葉澤光、發言人李定珠均未異動，確保財報編製與對外溝通之一致性，降低過渡期資訊斷層風險。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>華新科2023-2026的人事變動本質為「計畫性世代交替」，非異常訊號。唯稽核主管頻繁變動與PSA平台去個人化兩項，是2026-2027年持續追蹤的關鍵指標。若曾明燦在其任內第三年（2026）展現獨立穿越景氣循環之經營成果，接班風險將進一步降低。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>web_search</strong>：華新科 2492 董事/經理人異動 2023-2026 （鉅亨網/經濟日報/CTEE綜合）</li><li><strong>web_search</strong>：華新科 董事會名單 獨立董事 稽核主管 財務主管</li><li><strong>web_search</strong>：華新科 總經理輪調 2023年6月 曾明燦接任（MOPS重訊綜合）</li><li><strong>web_search</strong>：華新科 2025年11月 總經理異動（Goodinfo重訊編號）</li><li><strong>FinMind</strong>: 未使用</li></ul>',30)])])}const u=r(l,[["render",n]]);export{g as __pageData,u as default};
